sql:
SELECT designer_name
FROM designers
WHERE designer_id IN (
  SELECT designer_id
  FROM design_projects
);

SELECT project_name
FROM design_projects
WHERE status = 'in progress';

SELECT COUNT(*) AS project_count
FROM design_projects
WHERE status = 'in progress';

external_knowledge:
; The hierarchy level represents the position of a designer within the organizational structure, with higher levels indicating more senior roles; 
; A higher measurement count indicates more activity by the designer; 
; The total measurements for customers reflect the volume of work associated with each designer.
